#!/usr/bin/env bash
# Batch 2a: mattoni-cz (13) + mattoni-en (12) + mattoni-de (12) + queens-menu (2) + tmf-caje (11) + riva-del-garda (9) = 59 pages
set -euo pipefail
BASE="$(dirname "$0")/canva"

dl() {
  local dir="$BASE/$1" page="$2" url="$3"
  mkdir -p "$dir"
  local out="$dir/page-$(printf '%02d' $page).jpg"
  if [ -f "$out" ] && [ "$(stat -f%z "$out" 2>/dev/null || echo 0)" -gt 1000 ]; then
    echo "  skip $1/page-$(printf '%02d' $page) (exists)"
    return
  fi
  local status
  status=$(curl -sL -o "$out" -w "%{http_code}" "$url")
  local size
  size=$(stat -f%z "$out" 2>/dev/null || echo 0)
  if [ "$status" = "200" ] && [ "$size" -gt 1000 ]; then
    echo "  ✓ $1/page-$(printf '%02d' $page)"
  else
    echo "  ✗ $1/page-$(printf '%02d' $page) (HTTP $status, size $size)"
  fi
}

